async loadSessions(showLoading = false) {
    if (!this.currentRole) {return}
    if (showLoading) {this.sessionsLoading = true}
    try {
        this.sessions = await dailyReportAiApis.getSessionList(this.currentRole.id)
    } finally {
        this.sessionsLoading = false
    }
}

async loadSession(sessionId: number) {
    // 切换会话时中断正在进行的流式请求
    if (this.streamAbort) {
        this.streamAbort.abort()
        this.streamAbort = null
    }
    this.isStreaming = false
    this.currentSessionId = sessionId
    // 切换会话时重置意图识别状态，防止残留上一次的槽位结果
    this.slotsConversationId = ''
    this.lastSlotResult = null
    this.reportContext = ''
    this.pendingSlotMessages = []
    this.accumulatedContextChars = 0
    this.messagesLoading = true
    try {
        const msgs = await dailyReportAiApis.getSessionMessages(sessionId)
        this.messages = msgs.map(m => ({
            role: m.role,
            content: m.content,
            _id: m.id,
            _truncated: m.is_truncated || false,
            _fullLength: m.full_length || 0,
        }))
        // 累加历史会话中已有的上下文原始字符数
        for (const m of this.messages) {
            if (m.role === 'context') {
                this.accumulatedContextChars += m._fullLength || m.content.length
            }
        }
        this.$nextTick(() => {
            this.scrollToBottom()
            // markdown 渲染后高度可能变化，再滚一次
            setTimeout(() => this.scrollToBottom(), 100)
        })
    } finally {
        this.messagesLoading = false
    }
}

newSession() {
    this.currentSessionId = null
    this.messages = []
    this.slotsConversationId = ''
    this.lastSlotResult = null
    this.reportContext = ''
    this.pendingSlotMessages = []
    this.accumulatedContextChars = 0
}

// ---- 聊天 ----
onKeydown(e: KeyboardEvent) {
    if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault()
        this.sendMessage()
    }
}

async sendMessage() {
    const text = this.inputText.trim()
    if (!text || !this.currentRole || this.isStreaming) {return}

    // 有手动同步的 reportContext 且从未做过意图识别 → 直接问答（跳过意图识别）
    if (this.reportContext && !this.lastSlotResult) {
        await this.sendAskMessage(text)
    } else {
        // 走意图识别：LLM 判断是分析已有数据还是查询新数据
        await this.sendExtractSlots(text)
    }
}

