/** 将 pendingSlotMessages 中最后一条 assistant 的 content 同步为 UI 上的最终值 */
private syncPendingAssistant(assistantIdx: number) {
    const finalContent = this.messages[assistantIdx]?.content
    if (!finalContent) { return }
    // 从后往前找最后一条 assistant，更新其 content
    for (let i = this.pendingSlotMessages.length - 1; i >= 0; i--) {
        if (this.pendingSlotMessages[i].role === 'assistant') {
            this.pendingSlotMessages[i].content = finalContent
            return
        }
    }
}

private async flushSlotMessages() {
    if (this.pendingSlotMessages.length === 0 || !this.currentRole) {return}
    const sessionId = await dailyReportAiApis.saveMessages({
        role_id: this.currentRole.id,
        session_id: this.currentSessionId,
        messages: this.pendingSlotMessages,
    })
    if (sessionId && !this.currentSessionId) {
        this.currentSessionId = sessionId
        await this.loadSessions()
    }
    this.pendingSlotMessages = []
}

