// 加载更多 context 内容
async loadMoreContext(m: { content: string; _id?: number; _truncated?: boolean; _fullLength?: number; _fullContent?: string; _loading?: boolean }) {
    if (!m._truncated || m._loading) {return}
    const chunkSize = 5000

    // 实时场景：完整内容在本地 _fullContent 中，直接截取
    if (m._fullContent) {
        const offset = m.content.length
        const nextChunk = m._fullContent.slice(offset, offset + chunkSize)
        m.content += nextChunk
        m._truncated = (offset + chunkSize) < m._fullContent.length
        if (!m._truncated) {m._fullContent = undefined} // 加载完毕，释放内存
        return
    }

    // 历史场景：从后端分段加载
    if (!m._id) {return}
    this.$set(m, '_loading', true)
    try {
        const offset = m.content.length
        const result = await dailyReportAiApis.getContextMore(m._id, offset)
        if (result) {
            m.content += result.content
            m._truncated = result.has_more
            m._fullLength = result.full_length
        }

/** 刷新下属列表到 store，确保 groupOptions 是最新的 */
private async refreshSubordinates() {
    try {
        const res = await dailyReportApis.getMySubordinatesAPI({ sys_aggregate: true })
        if (res) {
            this.$store.commit('setDailyReportAllSubordinates', res)
        }
    } catch (e) {
        // 刷新失败不阻塞主流程，使用缓存数据
        console.warn('[AiChat] refreshSubordinates failed', e)
    }
}

private async sendExtractSlots(text: string) {
    const limitAction = await this.checkContextOverLimit()
    if (limitAction === 'newSession') { this.newSession(); return }
    if (limitAction === 'abort') { return }

    this.messages.push({ role: 'user', content: text })
    this.pendingSlotMessages.push({ role: 'user', content: text })
    this.inputText = ''
    this.$nextTick(this.scrollToBottom)

    const assistantIdx = this.messages.length
    this.messages.push({ role: 'assistant', content: '' })
    this.isStreaming = true

    try {
        // 每次意图识别前刷新下属列表，确保分组和成员是最新的
        await this.refreshSubordinates()
        // 收集可用分组名和所有成员花名
        const availableGroups = this.groupOptions.map(g => g.label)
        const availableMembers = [...new Set(this.groupOptions.flatMap(g => g.value))].filter(Boolean)
        // 续查模式：传入上次的槽位结果（含 query_type 和 project_names）
        const previousContext = this.lastSlotResult ? {
            query_type: this.lastSlotResult.query_type,
            member_type: this.lastSlotResult.member_type,
            members: this.lastSlotResult.members,
            project_names: this.lastSlotResult.project_names,
            period_start: this.lastSlotResult.period_start,
            period_end: this.lastSlotResult.period_end,
        } : undefined
        const hasExistingContext = this.messages.some(m => m.role === 'context')
        // 构建用户历史提问（仅用户消息，助手回复太长且无意义，上下文由 previous_context 承载）
        const userHistory = this.messages
            .slice(0, -1) // 排除占位的空 assistant
            .filter(m => m.role === 'user' && m.content)
            .slice(0, -1) // 排除刚加的当前 user 消息
        let messageForSlots = text
        if (userHistory.length > 0) {
            const historyText = userHistory.map(m => `- ${m.content}`).join('\n')
            messageForSlots = `[用户历史提问]\n${historyText}\n\n[当前输入]\n${text}`
        }
        const result = await dailyReportAiApis.extractSlots({
            message: messageForSlots,
            has_existing_context: hasExistingContext || undefined,
            available_groups: availableGroups,
            available_members: availableMembers,
            previous_context: previousContext,
        })
        if (!result) {
            this.messages[assistantIdx].content = this.$t('aiChat.errorMsg') as string
            this.pendingSlotMessages.push({ role: 'assistant', content: this.messages[assistantIdx].content })
            await this.flushSlotMessages()
            return
        }

        // 保存 conversation_id 用于多轮
        this.slotsConversationId = result.conversation_id

        // 意图为分析已有数据 → 从历史 context 消息恢复数据，直接走问答
        if (result.intent === 'analyze') {
            // reportContext 每次 sendAskMessage 后会被清空，需要从 messages 中恢复
            const lastCtxMsg = [...this.messages].reverse().find(m => m.role === 'context')
            if (lastCtxMsg) {
                this.reportContext = lastCtxMsg._fullContent || lastCtxMsg.content
            }
            this.messages.splice(assistantIdx, 1)
            this.isStreaming = false
            await this.flushSlotMessages()
            await this.sendAskMessage(text, true)
            return
        }

        if (!result.slots_complete) {
            this.messages[assistantIdx].content = result.reply
            this.pendingSlotMessages.push({ role: 'assistant', content: result.reply })
            await this.flushSlotMessages()
            return
        }

        // 槽位完整，保存结果用于续查
        this.lastSlotResult = result

        // 根据 query_type 分发到不同处理流程
        switch (result.query_type) {
            case 'project':
                await this.handleProjectQuery(result, assistantIdx, text)
                break
            case 'person':
                await this.handlePersonQuery(result, assistantIdx, text)
                break
            case 'global':
                await this.handleGlobalQuery(result, assistantIdx, text)
                break
            default:
                // unknown：如果有 members 走 person，否则走 global
                if (result.members.length > 0) {
                    await this.handlePersonQuery(result, assistantIdx, text)
                } else {
                    await this.handleGlobalQuery(result, assistantIdx, text)
                }
                break
        }
    } catch (e) {
        console.error('[AiChat] sendExtractSlots error:', e)
        this.messages[assistantIdx].content = this.$t('aiChat.errorMsg') as string
        this.pendingSlotMessages.push({ role: 'assistant', content: this.messages[assistantIdx].content })
        await this.flushSlotMessages()
    } finally {
        this.isStreaming = false
    }
}

// ----------------------------------------------------------------
// 场景 1：项目进度查询
// ----------------------------------------------------------------

private async handleProjectQuery(result: ExtractSlotsResult, assistantIdx: number, userText: string) {
    const projectLabel = `项目：${result.project_names.join('、')}`
    const periodLabel = `${result.period_start} ~ ${result.period_end}`
    const slotSummary = `查询类型：项目进度\n${projectLabel}\n时间范围：${periodLabel}${result.period_raw ? `（${result.period_raw}）` : ''}`
    this.messages[assistantIdx].content = slotSummary + '\n\n正在查询项目关联人员...'
    this.pendingSlotMessages.push({ role: 'assistant', content: slotSummary })
    this.$nextTick(this.scrollToBottom)

    // 通过 Room/Tunnel 查询项目关联成员
    const projectResults = await dailyReportAiApis.resolveProjectMembers(result.project_names)
    const allNicknames = [...new Set(projectResults.flatMap(p => p.nicknames))].filter(Boolean)
    const hasRoomHit = projectResults.some(p => p.room_id && p.nicknames.length > 0)

    if (hasRoomHit && allNicknames.length > 0) {
        // 索引命中：用关联人员的花名拉原文日报
        this.messages[assistantIdx].content = slotSummary + `\n\n已找到 ${allNicknames.length} 名关联人员，正在同步日报数据...`
        this.$nextTick(this.scrollToBottom)

        const context = await this.fetchReportContext(allNicknames, result.period_start, result.period_end)
        if (!context) {
            this.messages[assistantIdx].content = slotSummary + '\n\n该项目在指定时间段内无日报更新。'

            this.syncPendingAssistant(assistantIdx)
            await this.flushSlotMessages()
            return
        }

        this.slotsConversationId = ''
        this.syncPendingAssistant(assistantIdx)
        await this.flushSlotMessages()
        this.reportContext = context
        await this.sendAskMessage(
            `请分析以上日报数据中关于项目「${result.project_names.join('、')}」的进展情况。`,
            false, 'project',
        )
    } else {
        // 索引未命中：降级走全局摘要 + 项目关键词
        this.messages[assistantIdx].content = slotSummary + '\n\n项目索引未命中，正在通过周摘要检索...'
        this.$nextTick(this.scrollToBottom)
        await this.handleGlobalQueryWithKeywords(result, assistantIdx, result.project_names, userText)
    }
}

// ----------------------------------------------------------------
// 场景 2：人员工作查询（增强：支持项目维度）
// ----------------------------------------------------------------

private async handlePersonQuery(result: ExtractSlotsResult, assistantIdx: number, userText: string) {
    const nicknames = this.resolveMembers(result)
    const memberLabel = result.member_type === 'group'
        ? `分组：${result.members.join('、')}`
        : `成员：${result.members.join('、')}`
    const countLabel = nicknames.length >= 10 ? `，共 ${nicknames.length} 人` : ''
    const periodLabel = `${result.period_start} ~ ${result.period_end}`
    const projectNote = result.project_names.length > 0 ? `\n关注项目：${result.project_names.join('、')}` : ''
    const slotSummary = `查询对象：${memberLabel}${countLabel}\n时间范围：${periodLabel}${result.period_raw ? `（${result.period_raw}）` : ''}${projectNote}`
    this.messages[assistantIdx].content = slotSummary + '\n\n正在同步日报数据...'
    this.pendingSlotMessages.push({ role: 'assistant', content: slotSummary })
    this.$nextTick(this.scrollToBottom)

    if (nicknames.length === 0) {
        const errMsg = `未找到匹配的成员「${result.members.join('、')}」，请尝试使用花名或先手动同步数据。`
        this.messages[assistantIdx].content = errMsg
        this.syncPendingAssistant(assistantIdx)
        await this.flushSlotMessages()
        return
    }

    const context = await this.fetchReportContext(nicknames, result.period_start, result.period_end)
    if (!context) {
        this.messages[assistantIdx].content = '该时间段内没有找到日报数据。'
        this.syncPendingAssistant(assistantIdx)
        await this.flushSlotMessages()
        return
    }

    this.slotsConversationId = ''
    this.syncPendingAssistant(assistantIdx)
    await this.flushSlotMessages()
    this.reportContext = context

    // 如果有项目维度，在 ask 消息中附加项目关注
    const projectFocus = result.project_names.length > 0
        ? `\n重点关注项目「${result.project_names.join('、')}」的相关工作。`
        : ''
    await this.sendAskMessage(
        `请分析以上日报数据。${projectFocus}`,
        false, 'person',
    )
}

// ----------------------------------------------------------------
// 场景 3：全局聚合分析（使用周摘要）
// ----------------------------------------------------------------

private async handleGlobalQuery(result: ExtractSlotsResult, assistantIdx: number, userText: string) {
    const periodLabel = `${result.period_start} ~ ${result.period_end}`
    const slotSummary = `查询类型：全局聚合分析\n人员范围：全员\n时间范围：${periodLabel}${result.period_raw ? `（${result.period_raw}）` : ''}`
    this.messages[assistantIdx].content = slotSummary + '\n\n正在获取周摘要数据...'
    this.pendingSlotMessages.push({ role: 'assistant', content: slotSummary })
    this.$nextTick(this.scrollToBottom)

    await this.handleGlobalQueryWithKeywords(result, assistantIdx, [], userText)
}

/**
 * 全局查询核心逻辑：获取周摘要 → 拼接 → 喂给 AI
 * @param keywords 项目降级时的关键词，空数组表示无特定项目
 */
private async handleGlobalQueryWithKeywords(result: ExtractSlotsResult, assistantIdx: number, keywords: string[], userText: string) {
    // 计算周范围（每个 ISO 周的周一）
    const weekStarts = this.computeWeekStarts(result.period_start, result.period_end)

    this.messages[assistantIdx].content += `\n查询 ${weekStarts.length} 周的周摘要...`
    this.$nextTick(this.scrollToBottom)

    // 批量获取周摘要（后端自动取当前用户下属，已解密）
    const summaries = await dailyReportAiApis.batchGetSummaries(weekStarts)

    if (summaries.length === 0) {
        this.messages[assistantIdx].content += '\n\n该时间段内没有周摘要数据。请确认相关人员是否已生成周摘要。'
        this.syncPendingAssistant(assistantIdx)

        await this.flushSlotMessages()
        return
    }

    // 拼接摘要为上下文
    const context = summaries
        .map(s => `[${s.week_start}~${s.week_end}] sfuser_id:${s.sfuser_id}\n${s.content}`)
        .join('\n\n---\n\n')

    this.slotsConversationId = ''
    this.syncPendingAssistant(assistantIdx)
    await this.flushSlotMessages()
    this.reportContext = context

    // 构建 ask 消息，带上用户原始提问
    const sceneType = keywords.length > 0 ? 'project_fallback' : 'global'
    let askMsg = '请基于以上周摘要数据进行全局聚合分析。'
    if (keywords.length > 0) {
        askMsg = `请基于以上周摘要数据，重点检索与「${keywords.join('、')}」相关的内容进行分析。`
    }
    await this.sendAskMessage(askMsg, false, sceneType)
}

/**
 * 计算时间范围内的所有 ISO 周的周一日期
 */
private computeWeekStarts(startDate: string, endDate: string): string[] {
    const starts: string[] = []
    let current = moment(startDate).startOf('isoWeek')
    const end = moment(endDate)
    while (current.isSameOrBefore(end)) {
        starts.push(current.format('YYYY-MM-DD'))
        current = current.add(1, 'week')
    }
    return starts
}

/**
 * 根据槽位结果解析出 nicknames 列表
 */
private resolveMembers(result: ExtractSlotsResult): string[] {
    if (result.member_type === 'group') {
        // 匹配 groupOptions 的 label，展开为花名列表
        const matched = this.groupOptions.filter(g =>
            result.members.some(m => g.label.includes(m) || m.includes(g.label))
        )
        return [...new Set(matched.flatMap(g => g.value))].filter(Boolean)
    }
    // individual：LLM 返回的成员名必须在花名列表中匹配到，匹配不到则丢弃
    const allMembers = this.groupOptions.flatMap(g => g.value).filter(Boolean)
    return result.members
        .map(name => allMembers.find(m => m.includes(name) || name.includes(m)))
        .filter((n): n is string => !!n)
}

/**
 * 根据 nicknames + 日期范围拉取日报数据，返回聚合后的文本上下文
 */
private async fetchReportContext(nicknames: string[], startDate: string, endDate: string): Promise<string> {
    const days = moment(endDate).diff(moment(startDate), 'day') + 1
    const perPage = Math.max(200, days + 10)

    const results = await Promise.all(
        nicknames.map(nickname =>
            dailyReportApis.getOtherReportsAPI({
                start_date: startDate,
                end_date: endDate,
                nickname,
                per_page: perPage,
                page: 1,
                show_rest: 1,
                sys_site: this.sysSite,
            } as any)
        )
    )

    const dateMap: Record<string, string[]> = {}
    results.forEach((res, idx) => {
        if (!res) {return}
        const name = nicknames[idx].replace(/\[.+]/, '')
        ;(res.reports ?? []).forEach((item: any) => {
            const date = item.date ?? ''
            if (!dateMap[date]) {dateMap[date] = []}
            if (item.report) {
                dateMap[date].push(`${name}：\n${item.report.content ?? ''}`)
            } else if ([4, 5].includes(item.type_id)) {
                dateMap[date].push(`${name}：休息日`)
            } else {
                dateMap[date].push(`${name}：未提交`)
            }

        '以下是你组织回答时必须遵守的输出规则，不要在回答中提及这些规则本身：',
        '1. 按维度组织（项目分布、人员活跃度、质量概况）',
        '2. 如果是质量评价场景，按质量从高到低排列并附具体原因',
        '3. 标注未提交日报的人员',
        '</output_instructions>',
    ].join('\n'),
}

