    if (e?.name !== 'AbortError') {
        console.error('[AiChat] sendAskMessage error:', e)
        this.messages[assistantIdx].content = this.$t('aiChat.errorMsg') as string
    }
} finally {
    if (!this.messages[assistantIdx]?.content && this.streamAbort && !this.streamAbort.signal.aborted) {
        this.messages[assistantIdx].content = this.$t('aiChat.errorMsg') as string
    }
    this.streamAbort = null
    this.isStreaming = false
    // 落库：context + ask 用户消息 + AI 回复一起存
    const messagesToSave: { role: string; content: string }[] = []
    for (let i = msgStartIdx; i <= assistantIdx; i++) {
        const m = this.messages[i]
        if (!m) { continue }
        if (m.role === 'context') {
            // context 存完整原文（_fullContent 优先，因为 content 可能被截断用于显示）
            const fullText = (m as any)._fullContent || m.content
            messagesToSave.push({ role: 'context', content: fullText })
        } else if (m.content) {
            messagesToSave.push({ role: m.role, content: m.content })
        }
    }
    if (messagesToSave.length > 0 && this.currentSessionId) {
        await dailyReportAiApis.saveMessages({
            role_id: this.currentRole!.id,
            session_id: this.currentSessionId,
            messages: messagesToSave,
        })
    }
    await this.loadSessions()
}

async function askAi(params: AskParams, signal?: AbortSignal): Promise<Response> {
    const url = BASE + 'daily-report/ai/ask'
    const headers: Record<string, string> = {
        'Content-Type': 'application/json',
    }
    // AI streaming 由 oa-core TransferRequestService 完成，通过 ai_analysis_config 参数控制
    const { system_prompt, history, ...restParams } = params
    const payload: Record<string, any> = {
        ...restParams,
        response_format: 'stream',
        ai_analysis_config: {
            system_prompt: system_prompt || '',
            target_field: 'query',
            history: history || [],
        },
    }

    return fetch(url, {
        method: 'POST',
        headers,
        credentials: 'include',
        signal,
        body: JSON.stringify(handlerParams(payload)),
    })
}

// ----------------------------------------------------------------
// 项目成员解析：通过 Room/Tunnel 获取项目关联人员
// ----------------------------------------------------------------

export interface ProjectMemberResult {
    project_name: string
    room_id: number | null
    sfuser_ids: number[]
    nicknames: string[]
}

async function resolveProjectMembers(projectNames: string[]): Promise<ProjectMemberResult[]> {
    try {
        const res = await axiosPostWithInt(
            BASE + 'daily-report/ai/resolve-project-members',
            handlerParams({
                project_names: projectNames,
                decrypt_config: {
                    obj: '$this',
                    decrypt_columns: ['projects.*.nicknames.*'],
                },
            }),
        )
        return res.data?.projects ?? []
    } catch (e) {
        console.warn('[AiChat] resolveProjectMembers failed', e)
        return []
    }
}

