177→/**
178→ * 从 AI 原始文本中解析槽位 JSON，兼容 markdown 代码块包裹
179→ */
180→function parseSlotJson(text: string): ExtractSlotsResult {
181→    const fallback: ExtractSlotsResult = {
182→        intent: 'new_query',
183→        query_type: 'unknown',
184→        slots_complete: false,
185→        members: [],
186→        member_type: '',
187→        project_names: [],
188→        period_start: '',
189→        period_end: '',
190→        period_raw: '',
191→        reply: '抱歉没理解你的意思，请告诉我你想查哪个分组或具体成员的日报，以及查哪个时间段？',
192→        conversation_id: '',
193→    }
194→    const match = text.match(/\{[\s\S]*\}/)
195→    if (!match) {
196→        console.warn('[AiSlots] no JSON found in answer', text.slice(0, 500))
197→        return fallback
198→    }
199→    try {
200→        const data = JSON.parse(match[0])
201→        return {
202→            intent: data.intent ?? 'new_query',
203→            query_type: data.query_type ?? 'unknown',
204→            slots_complete: !!data.slots_complete,
205→            members: data.members ?? [],
206→            member_type: data.member_type ?? '',
207→            project_names: data.project_names ?? [],
208→            period_start: data.period_start ?? '',
209→            period_end: data.period_end ?? '',
210→            period_raw: data.period_raw ?? '',
211→            reply: data.reply ?? '',
212→            conversation_id: '',
213→        }
214→    } catch {
215→        console.warn('[AiSlots] JSON parse failed', match[0].slice(0, 500))
216→        return fallback
217→    }
218→}
