220→async function extractSlots(params: {
221→    message: string
222→    conversation_id?: string
223→    has_existing_context?: boolean
224→    available_groups?: string[]
225→    available_members?: string[]
226→    previous_context?: { query_type: string; member_type: string; members: string[]; project_names: string[]; period_start: string; period_end: string }
227→}): Promise<ExtractSlotsResult | null> {
228→    try {
229→        const res = await axiosPostWithInt(BASE + 'daily-report/ai/extract-slots', handlerParams(params))
230→        // oa-server 返回 { message, ai_analysis_config }，oa-core TransferRequestService 做 blocking AI，结果在 ai_result
231→        const aiResult = res.data?.ai_result ?? ''
232→        if (!aiResult) {
