524→
525→        $message = $request->input('message');
526→        $conversationId = $request->input('conversation_id', '');
527→        $availableGroups = $request->input('available_groups', []);
528→        $availableMembers = $request->input('available_members', []);
529→        $previousContext = $request->input('previous_context');
530→        $hasExistingContext = $request->boolean('has_existing_context', false);
531→
532→        // 查询所有活跃项目名（含别名），供 AI 匹配
533→        $projectList = $this->getAvailableProjects();
534→        $projectListText = !empty($projectList)
535→            ? implode('、', $projectList)
536→            : '（暂无已有项目）';
537→
538→        // 将可用分组和成员列表格式化为 prompt 中的列表
539→        $groupList = !empty($availableGroups)
540→            ? implode("\n", array_map(fn ($g) => "   - {$g}", $availableGroups))
541→            : '   - （无可用分组）';
542→        $memberList = !empty($availableMembers)
543→            ? implode('、', $availableMembers)
544→            : '（无可用成员列表）';
545→
546→        // 上次查询上下文：首次查询时为"无"，续查时包含上次的成员、周期和项目
547→        $prevCtx = '无（首次查询）';
548→        if (!empty($previousContext)) {
549→            $parts = [];
550→            $prevQueryType = $previousContext['query_type'] ?? 'person';
551→            $parts[] = "查询类型：{$prevQueryType}";
552→            if (!empty($previousContext['members'])) {
553→                $prevMembers = implode('、', $previousContext['members']);
554→                $prevType = ($previousContext['member_type'] ?? '') === 'group' ? '分组' : '成员';
555→                $parts[] = "查询{$prevType}：{$prevMembers}";
556→            }
557→            if (!empty($previousContext['project_names'])) {
558→                $parts[] = '项目：'.implode('、', $previousContext['project_names']);
559→            }
560→            $prevPeriod = ($previousContext['period_start'] ?? '').' ~ '.($previousContext['period_end'] ?? '');
561→            $parts[] = "周期：{$prevPeriod}";
562→            $prevCtx = implode('，', $parts);
563→        }
564→
565→        $hasContextLabel = $hasExistingContext ? '是' : '否';
566→        $systemPrompt = sprintf(
567→            self::SLOT_EXTRACTION_PROMPT,
568→            $hasContextLabel,
569→            $projectListText,
570→            $groupList,
571→            $memberList,
572→            now()->toDateString(),
573→            $prevCtx,
574→        );
575→
576→        \Log::info('[lbl][0416-AI日报][AiSlots] request', [
577→            'sfuser_id' => $sfuserId,
578→            'message' => $message,
579→            'previous_context' => $previousContext,
580→            'available_groups' => $availableGroups,
581→            'member_count' => count($availableMembers),
582→            'project_count' => count($projectList),
583→        ]);
584→
585→        return $this->responseJsonSuccess([
586→            'message' => $message,
587→            'ai_analysis_config' => [
588→                'system_prompt' => $systemPrompt,
589→                'target_field' => 'message',
590→                'output_field' => 'ai_result',
591→            ],
592→        ]);
