private async handleGlobalQuery(result: ExtractSlotsResult, assistantIdx: number, userText: string) {
    const periodLabel = `${result.period_start} ~ ${result.period_end}`
    const slotSummary = `查询类型：全局聚合分析\n人员范围：全员\n时间范围：${periodLabel}${result.period_raw ? `（${result.period_raw}）` : ''}`
    this.messages[assistantIdx].content = slotSummary + '\n\n正在获取周摘要数据...'
    this.pendingSlotMessages.push({ role: 'assistant', content: slotSummary })
    this.$nextTick(this.scrollToBottom)

    await this.handleGlobalQueryWithKeywords(result, assistantIdx, [], userText)
}

/**
 * 全局查询核心逻辑：获取周摘要 → 拼接 → 喂给 AI
 * @param keywords 项目降级时的关键词，空数组表示无特定项目
 */
private async handleGlobalQueryWithKeywords(result: ExtractSlotsResult, assistantIdx: number, keywords: string[], userText: string) {
    // 计算周范围（每个 ISO 周的周一）
    const weekStarts = this.computeWeekStarts(result.period_start, result.period_end)

    this.messages[assistantIdx].content += `\n查询 ${weekStarts.length} 周的周摘要...`
    this.$nextTick(this.scrollToBottom)

    // 批量获取周摘要（后端自动取当前用户下属，已解密）
    const summaries = await dailyReportAiApis.batchGetSummaries(weekStarts)

    if (summaries.length === 0) {
        this.messages[assistantIdx].content += '\n\n该时间段内没有周摘要数据。请确认相关人员是否已生成周摘要。'
        this.syncPendingAssistant(assistantIdx)
        await this.flushSlotMessages()
        return
    }

    // 拼接摘要为上下文
    const context = summaries
        .map(s => `[${s.week_start}~${s.week_end}] sfuser_id:${s.sfuser_id}\n${s.content}`)
        .join('\n\n---\n\n')

    this.slotsConversationId = ''
    this.syncPendingAssistant(assistantIdx)
    await this.flushSlotMessages()
    this.reportContext = context

    // 构建 ask 消息，带上用户原始提问
    const sceneType = keywords.length > 0 ? 'project_fallback' : 'global'
    let askMsg = '请基于以上周摘要数据进行全局聚合分析。'
    if (keywords.length > 0) {
        askMsg = `请基于以上周摘要数据，重点检索与「${keywords.join('、')}」相关的内容进行分析。`
    }
    await this.sendAskMessage(askMsg, false, sceneType)
}

/**
 * 计算时间范围内的所有 ISO 周的周一日期
 */
private computeWeekStarts(startDate: string, endDate: string): string[] {
    const starts: string[] = []
    let current = moment(startDate).startOf('isoWeek')
    const end = moment(endDate)
    while (current.isSameOrBefore(end)) {
        starts.push(current.format('YYYY-MM-DD'))
        current = current.add(1, 'week')
    }
    return starts
}

/**
 * 根据槽位结果解析出 nicknames 列表
 */
private resolveMembers(result: ExtractSlotsResult): string[] {
    if (result.member_type === 'group') {
        // 匹配 groupOptions 的 label，展开为花名列表
        const matched = this.groupOptions.filter(g =>
            result.members.some(m => g.label.includes(m) || m.includes(g.label))
        )
        return [...new Set(matched.flatMap(g => g.value))].filter(Boolean)
    }
    // individual：LLM 返回的成员名必须在花名列表中匹配到，匹配不到则丢弃
    const allMembers = this.groupOptions.flatMap(g => g.value).filter(Boolean)
    return result.members
        .map(name => allMembers.find(m => m.includes(name) || name.includes(m)))
        .filter((n): n is string => !!n)

