const assistantIdx = this.messages.length
this.messages.push({ role: 'assistant', content: '' })
this.isStreaming = true

const newContextChars = contextToSend ? contextToSend.length : 0
const limitAction = await this.checkContextOverLimit(newContextChars)
if (limitAction !== 'ok') {
    this.messages.splice(msgStartIdx)
    this.isStreaming = false
    if (limitAction === 'newSession') { this.newSession() }
    return
}

this.streamAbort = new AbortController()
try {
    const history = this.messages.slice(0, -2).filter(m => m.role !== 'context' && !!m.content).slice(-10) as { role: 'user' | 'assistant'; content: string }[]
    const processedContext = contextToSend ? compressDailyContext(contextToSend) : ''
    if (processedContext) {
        console.info('[AiChat] 压缩前上下文:\n', processedContext)
    }
    const compressedContext = processedContext ? await compressContext(processedContext) : ''
    const response = await dailyReportAiApis.askAi({
        role_id: this.currentRole!.id,
        session_id: this.currentSessionId,
        message: text,
        report_context: compressedContext,
        report_context_raw: contextToSend ? await compressContext(contextToSend) : undefined,
        system_prompt: this.currentRole!.system_prompt
            + (sceneType && this.SCENE_OUTPUT_RULES[sceneType] || ''),
        history,
    }, this.streamAbort.signal)

    const reader = response.body!.getReader()
    const decoder = new TextDecoder()
    let buffer = ''

    while (true) {
        const { done, value } = await reader.read()
        if (done) {break}
        buffer += decoder.decode(value, { stream: true })
        const lines = buffer.split('\n')
        buffer = lines.pop() ?? ''

        for (const line of lines) {
            if (!line.startsWith('data: ')) {continue}
            try {
                const parsed = JSON.parse(line.slice(6))
                if (parsed.error_code !== 0) {
                    this.messages[assistantIdx].content = this.$t('aiChat.errorMsg') as string
                    break
                }
                const data = parsed.data
                // TransferRequestService SSE 格式：meta（首帧，含 session_id）+ chat（流式内容）
                if (data.type === 'meta') {
                    if (data.session_id && !this.currentSessionId) {
                        this.currentSessionId = Number(data.session_id)
                        this.loadSessions()
                    }
                } else if (data.type === 'chat' && data.content) {
                    this.messages[assistantIdx].content += data.content
                    this.$nextTick(this.scrollToBottom)
                }
            } catch {}
        }
    }
    // 流式读取完成，累加本次上下文字符数
    if (newContextChars > 0) {
        this.accumulatedContextChars += newContextChars
    }
} catch (e: any) {
    if (e?.name !== 'AbortError') {
        console.error('[AiChat] sendAskMessage error:', e)
        this.messages[assistantIdx].content = this.$t('aiChat.errorMsg') as string
    }
} finally {
    if (!this.messages[assistantIdx]?.content && this.streamAbort && !this.streamAbort.signal.aborted) {
        this.messages[assistantIdx].content = this.$t('aiChat.errorMsg') as string
    }
    this.streamAbort = null
    this.isStreaming = false
    // 落库：仅保存 AI 回复（context 和 user 消息已由后端 ask 接口保存，避免重复）
    const assistantContent = this.messages[assistantIdx]?.content
    if (assistantContent && this.currentSessionId) {
        await dailyReportAiApis.saveMessages({
            role_id: this.currentRole!.id,
            session_id: this.currentSessionId,
            messages: [{ role: 'assistant', content: assistantContent }],
        })
    }
    await this.loadSessions()

