// ----------------------------------------------------------------
// 意图识别：提取查询槽位
// ----------------------------------------------------------------

export interface ExtractSlotsResult {
    intent: 'analyze' | 'new_query'
    query_type: 'project' | 'person' | 'global' | 'unknown'
    slots_complete: boolean
    member_type: 'group' | 'individual' | ''
    members: string[]
    project_names: string[]
    period_start: string
    period_end: string
    period_raw: string
    reply: string
    conversation_id: string
}

/**
 * 从 AI 原始文本中解析槽位 JSON，兼容 markdown 代码块包裹
 */
function parseSlotJson(text: string): ExtractSlotsResult {
    const fallback: ExtractSlotsResult = {
        intent: 'new_query',
        query_type: 'unknown',
        slots_complete: false,
        members: [],
        member_type: '',
        project_names: [],
        period_start: '',
        period_end: '',
        period_raw: '',
        reply: '抱歉没理解你的意思，请告诉我你想查哪个分组或具体成员的日报，以及查哪个时间段？',
        conversation_id: '',
    }
    const match = text.match(/\{[\s\S]*\}/)
    if (!match) {
        console.warn('[AiSlots] no JSON found in answer', text.slice(0, 500))
        return fallback
    }
    try {
        const data = JSON.parse(match[0])
        return {
            intent: data.intent ?? 'new_query',
            query_type: data.query_type ?? 'unknown',
            slots_complete: !!data.slots_complete,
            members: data.members ?? [],
            member_type: data.member_type ?? '',
            project_names: data.project_names ?? [],
            period_start: data.period_start ?? '',
            period_end: data.period_end ?? '',
            period_raw: data.period_raw ?? '',
            reply: data.reply ?? '',
            conversation_id: '',
        }
    } catch {
        console.warn('[AiSlots] JSON parse failed', match[0].slice(0, 500))
        return fallback
    }
}

async function extractSlots(params: {
    message: string
    conversation_id?: string
    has_existing_context?: boolean
    available_groups?: string[]
    available_members?: string[]
    previous_context?: { query_type: string; member_type: string; members: string[]; project_names: string[]; period_start: string; period_end: string }
}): Promise<ExtractSlotsResult | null> {
    try {
        const res = await axiosPostWithInt(BASE + 'daily-report/ai/extract-slots', handlerParams(params))
        // oa-server 返回 { message, ai_analysis_config }，oa-core TransferRequestService 做 blocking AI，结果在 ai_result
        const aiResult = res.data?.ai_result ?? ''
        if (!aiResult) {
            return null
        }
        return parseSlotJson(aiResult)
    } catch (e) {
        Message.error(e?.error_msg || '意图识别失败')
        return null
    }
}

// ----------------------------------------------------------------
// 保存消息（意图识别阶段的对话落库）
// ----------------------------------------------------------------

async function saveMessages(params: {
    role_id: number
    session_id?: number | null
    messages: { role: string; content: string }[]
}): Promise<number | null> {
    try {
        const res = await axiosPostWithInt(BASE + 'daily-report/ai/save-messages', handlerParams(params as Record<string, any>))
        return res.data?.session_id ?? null
    } catch (e) {
        return null
    }
}

// ----------------------------------------------------------------
// 发送消息（SSE 流式）
// 返回 EventSource 风格的 ReadableStream，调用方自行消费
// ----------------------------------------------------------------

export interface AskParams {
    role_id: number
    session_id?: number | null
    message: string
    report_context?: string
    report_context_raw?: string
    history?: { role: 'user' | 'assistant'; content: string }[]
    system_prompt?: string
}

// ----------------------------------------------------------------
// 权限检查
// ----------------------------------------------------------------

async function checkAccess(): Promise<boolean> {
    try {
        const res = await axiosPostWithInt(BASE + 'daily-report/ai/check-access', handlerParams({}))
        return res.data?.has_access ?? false
    } catch (e) {
        return false
    }
}

async function checkGroupAccess(): Promise<boolean> {
    try {
        const res = await axiosPostWithInt(BASE + 'daily-report/ai/check-group-access', handlerParams({}))
        return res.data?.has_access ?? false
    } catch (e) {
        return false
    }
}

/**
 * 发送消息，返回 fetch Response（SSE）
 * 调用方通过 response.body.getReader() 读取流
 */
async function askAi(params: AskParams, signal?: AbortSignal): Promise<Response> {
    const url = BASE + 'daily-report/ai/ask'
    const headers: Record<string, string> = {
        'Content-Type': 'application/json',
    }
    // AI streaming 由 oa-core TransferRequestService 完成，通过 ai_analysis_config 参数控制
    const { system_prompt, history, ...restParams } = params
    const payload: Record<string, any> = {
        ...restParams,
        response_format: 'stream',
        ai_analysis_config: {
            system_prompt: system_prompt || '',
            target_field: 'query',
            history: history || [],
        },
    }

    return fetch(url, {
        method: 'POST',
        headers,
        credentials: 'include',
        signal,
        body: JSON.stringify(handlerParams(payload)),
    })
}

// ----------------------------------------------------------------
// 项目成员解析：通过 Room/Tunnel 获取项目关联人员
// ----------------------------------------------------------------

export interface ProjectMemberResult {
    project_name: string
    room_id: number | null
    sfuser_ids: number[]
    nicknames: string[]
}

async function resolveProjectMembers(projectNames: string[]): Promise<ProjectMemberResult[]> {
    try {
        const res = await axiosPostWithInt(
            BASE + 'daily-report/ai/resolve-project-members',
            handlerParams({
                project_names: projectNames,
                decrypt_config: {
                    obj: '$this',
                    decrypt_columns: ['projects.*.nicknames.*'],
                },
            }),
        )
        return res.data?.projects ?? []
    } catch (e) {
        console.warn('[AiChat] resolveProjectMembers failed', e)
        return []
    }
}

// ----------------------------------------------------------------
// 花名 → sfuser_id 映射
// ----------------------------------------------------------------

async function resolveNicknames(nicknames: string[]): Promise<Record<string, number>> {
    try {
        const res = await axiosPostWithInt(
            BASE + 'daily-report/ai/resolve-nicknames',
            handlerParams({
                nicknames,
                decrypt_config: {
                    obj: '$this',
                    decrypt_columns: ['mapping.*.nickname'],
                },
            }),
        )
        const mapping: Record<string, number> = {}
        for (const item of res.data?.mapping ?? []) {
            mapping[item.nickname] = item.sfuser_id
        }
        return mapping
    } catch (e) {
        console.warn('[AiChat] resolveNicknames failed', e)
        return {}
    }
}

// ----------------------------------------------------------------
// 批量获取周摘要（带解密）
// ----------------------------------------------------------------

export interface SummaryItem {
    sfuser_id: number
    week_start: string
    week_end: string
    content: string
    submit_days: number
    total_chars: number
}

async function batchGetSummaries(
    weekStarts: string[],
): Promise<SummaryItem[]> {
    try {
        const res = await axiosPostWithInt(
            BASE + 'daily-report/ai/batch-get-summaries',
            handlerParams({
                week_starts: weekStarts,
                decrypt_config: {
                    obj: '$this',
                    decrypt_columns: ['summaries.*.content'],
                },
            }),
        )
        return res.data?.summaries ?? []
    } catch (e) {
        console.warn('[AiChat] batchGetSummaries failed', e)
        return []
    }
}

export default {
    checkAccess,
    checkGroupAccess,
    getRoleList,
    createRole,
    updateRole,
    deleteRole,
    getPromptList,
    createPrompt,
    deletePrompt,
    getSessionList,
    getSessionMessages,
    getContextMore,
    askAi,
    extractSlots,
    saveMessages,
    resolveProjectMembers,
    resolveNicknames,
    batchGetSummaries,
}

