/** 估算可见人数（groupOptions 去重） */
private get visibleMemberCount(): number {
    const all = new Set(this.groupOptions.flatMap(g => g.value).filter(Boolean))
    return all.size
}

/**
 * 全局查询核心逻辑：根据数据量走直接路径或分批路径
 * @param keywords 项目降级时的关键词，空数组表示无特定项目
 */
private async handleGlobalQueryWithKeywords(result: ExtractSlotsResult, assistantIdx: number, keywords: string[], userText: string) {
    const weekStarts = this.computeWeekStarts(result.period_start, result.period_end)
    const estimatedChars = this.visibleMemberCount * weekStarts.length * 500
    const THRESHOLD = 200000

    this.messages[assistantIdx].content += `\n可见人数：${this.visibleMemberCount}，周数：${weekStarts.length}，预估数据量：${Math.round(estimatedChars / 10000)}万字`
    this.$nextTick(this.scrollToBottom)

    if (estimatedChars <= THRESHOLD) {
        await this.handleGlobalDirect(result, assistantIdx, weekStarts, keywords)
    } else {
        await this.handleGlobalBatch(result, assistantIdx, weekStarts, keywords)
    }
}

/** 直接路径：全员周摘要 + 未提交人员 → 一次 LLM */
private async handleGlobalDirect(result: ExtractSlotsResult, assistantIdx: number, weekStarts: string[], keywords: string[]) {
    this.messages[assistantIdx].content += '\n正在获取周摘要数据...'
    this.$nextTick(this.scrollToBottom)

    const [summaries, unreported] = await Promise.all([
        dailyReportAiApis.batchGetSummaries(weekStarts),
        dailyReportAiApis.getUnreportedUsers(result.period_start, result.period_end),
    ])

    if (summaries.length === 0 && unreported.length === 0) {
        this.messages[assistantIdx].content += '\n\n该时间段内没有周摘要数据。请确认相关人员是否已生成周摘要。'
        this.syncPendingAssistant(assistantIdx)
        await this.flushSlotMessages()
        return
    }

    // 拼接摘要
    let context = summaries
        .map(s => `[${s.week_start}~${s.week_end}] sfuser_id:${s.sfuser_id}\n${s.content}`)
        .join('\n\n---\n\n')

    // 附加未提交人员信息
    if (unreported.length > 0) {
        const names = unreported.map(u => u.nickname).filter(Boolean)
        context += `\n\n---\n\n【未提交日报人员（${result.period_start}~${result.period_end}期间完全未提交）】\n${names.join('、')}`
    }

    this.slotsConversationId = ''
    this.syncPendingAssistant(assistantIdx)
    await this.flushSlotMessages()
    this.reportContext = context

    const sceneType = keywords.length > 0 ? 'project_fallback' : 'global'
    let askMsg = '请基于以上周摘要数据进行全局聚合分析。'
    if (keywords.length > 0) {
        askMsg = `请基于以上周摘要数据，重点检索与「${keywords.join('、')}」相关的内容进行分析。`
    }
    await this.sendAskMessage(askMsg, false, sceneType)
}

/** 分批路径：按项目分组 → 逐项目 LLM 小结 → 汇总 + 未提交人员 → 最终 LLM */
private async handleGlobalBatch(result: ExtractSlotsResult, assistantIdx: number, weekStarts: string[], keywords: string[]) {
    this.messages[assistantIdx].content += '\n数据量较大，正在按项目分组分析...'
    this.$nextTick(this.scrollToBottom)

    const [projectGroups, unreported] = await Promise.all([
        dailyReportAiApis.getSummariesByProject(weekStarts),
        dailyReportAiApis.getUnreportedUsers(result.period_start, result.period_end),
    ])

    if (projectGroups.length === 0) {
        this.messages[assistantIdx].content += '\n\n该时间段内没有周摘要数据。'
        this.syncPendingAssistant(assistantIdx)
        await this.flushSlotMessages()
        return
    }

    // 逐项目 LLM 生成小结
    const projectSummaryResults: { project_name: string; summary: string }[] = []
    for (let i = 0; i < projectGroups.length; i++) {
        const group = projectGroups[i]
        this.messages[assistantIdx].content = this.messages[assistantIdx].content.replace(
            /正在按项目分组分析.*$/,
            `正在按项目分组分析... (${i + 1}/${projectGroups.length}) ${group.project_name}`,
        )
        this.$nextTick(this.scrollToBottom)

        const groupContext = group.summaries
            .map(s => `[${s.week_start}~${s.week_end}] sfuser_id:${s.sfuser_id}\n${s.content}`)
            .join('\n\n---\n\n')

        const summary = await this.askAiBlocking(
            groupContext,
            `请对项目「${group.project_name}」的以上周摘要进行概括小结，保留关键事实和进度状态，200字以内。`,
        )
        projectSummaryResults.push({ project_name: group.project_name, summary })
    }

    // 汇总所有项目小结 + 未提交人员
    let finalContext = projectSummaryResults
        .map(p => `【${p.project_name}】\n${p.summary}`)
        .join('\n\n---\n\n')

    if (unreported.length > 0) {
        const names = unreported.map(u => u.nickname).filter(Boolean)
        finalContext += `\n\n---\n\n【未提交日报人员（${result.period_start}~${result.period_end}期间完全未提交）】\n${names.join('、')}`
    }

    this.slotsConversationId = ''
    this.syncPendingAssistant(assistantIdx)
    await this.flushSlotMessages()
    this.reportContext = finalContext

    const sceneType = keywords.length > 0 ? 'project_fallback' : 'global'
    let askMsg = '请基于以上各项目小结进行全局聚合分析。'
    if (keywords.length > 0) {
        askMsg = `请基于以上各项目小结，重点分析与「${keywords.join('、')}」相关的内容。`
    }
    await this.sendAskMessage(askMsg, false, sceneType)
}

/**
 * Blocking 模式 AI 调用：消费完 SSE 流后返回完整文本，不写入 messages
 */
private async askAiBlocking(context: string, prompt: string): Promise<string> {
    try {
        const processedContext = compressDailyContext(context)
        const compressedContext = processedContext ? await compressContext(processedContext) : ''
        const response = await dailyReportAiApis.askAi({
            role_id: this.currentRole!.id,
            session_id: this.currentSessionId,
            message: prompt,
            report_context: compressedContext,
            system_prompt: this.currentRole!.system_prompt,
            history: [],
        })

        const reader = response.body!.getReader()
        const decoder = new TextDecoder()
        let buffer = ''
        let result = ''

        while (true) {
            const { done, value } = await reader.read()
            if (done) { break }
            buffer += decoder.decode(value, { stream: true })
            const lines = buffer.split('\n')
            buffer = lines.pop() ?? ''
            for (const line of lines) {
                if (!line.startsWith('data: ')) { continue }
                try {
                    const parsed = JSON.parse(line.slice(6))
                    if (parsed.error_code !== 0) { break }
                    if (parsed.data?.type === 'chat' && parsed.data.content) {
                        result += parsed.data.content
                    }
                } catch {}
            }
        }
        return result || '（小结生成失败）'
    } catch (e) {
        console.error('[AiChat] askAiBlocking error:', e)
        return '（小结生成失败）'
    }
}

