/**
 * 周摘要相关工具函数
 * ISO 周定义：周一为一周起始，周日为一周结束
 */

/**
 * 计算指定日期所在 ISO 周的边界（周一~周日）
 */
export function getWeekBounds(dateStr: string): { week_start: string; week_end: string } {
    const d = new Date(dateStr)
    const day = d.getDay() // 0=Sun, 1=Mon, ..., 6=Sat
    // 偏移到周一：周日需要回退 6 天，其他天回退 (day - 1) 天
    const diffToMonday = day === 0 ? -6 : 1 - day
    const monday = new Date(d)
    monday.setDate(d.getDate() + diffToMonday)

    const sunday = new Date(monday)
    sunday.setDate(monday.getDate() + 6)

    return {
        week_start: formatDate(monday),
        week_end: formatDate(sunday),
    }
}

/**
 * 上周的周一~周日
 */
export function getLastWeekBounds(today: string): { week_start: string; week_end: string } {
    const d = new Date(today)
    d.setDate(d.getDate() - 7)
    return getWeekBounds(formatDate(d))
}

/**
 * 本周的周一~周日
 */
export function getCurrentWeekBounds(today: string): { week_start: string; week_end: string } {
    return getWeekBounds(today)
}

/**
 * 是否为周五、周六或周日
 */
export function isFridayOrWeekend(dateStr: string): boolean {
    const day = new Date(dateStr).getDay()
    return day === 5 || day === 6 || day === 0
}

/**
 * 获取星期几（0=Sun, 1=Mon, ..., 6=Sat）
 */
export function getDayOfWeek(dateStr: string): number {
    return new Date(dateStr).getDay()
}

/**
 * 从日报列表中计算摘要统计数据
 * @param reports 日报列表，每项需包含 content(string) 和 report_date(string)
 */
export function computeSummaryStats(
    reports: Array<{ content?: string; report_date?: string }>,
): { total_chars: number; submit_days: number } {
    let totalChars = 0
    const submittedDates = new Set<string>()

    for (const report of reports) {
        if (report.content) {
            // 去掉 HTML 标签后计算字数
            const text = report.content.replace(/<[^>]+>/g, '')
            totalChars += text.length
        }
        if (report.report_date) {
            submittedDates.add(report.report_date)
        }
    }

    return {
        total_chars: totalChars,
        submit_days: submittedDates.size,
    }
}

/**
 * 格式化 Date 为 YYYY-MM-DD
 */
function formatDate(d: Date): string {
    const year = d.getFullYear()
    const month = String(d.getMonth() + 1).padStart(2, '0')
    const day = String(d.getDate()).padStart(2, '0')
    return `${year}-${month}-${day}`
}

