private async handleProjectQuery(result: ExtractSlotsResult, assistantIdx: number, userText: string) {
    const projectLabel = `项目：${result.project_names.join('、')}`
    const periodLabel = `${result.period_start} ~ ${result.period_end}`
    const slotSummary = `查询类型：项目进度\n${projectLabel}\n时间范围：${periodLabel}${result.period_raw ? `（${result.period_raw}）` : ''}`
    this.messages[assistantIdx].content = slotSummary + '\n\n正在查询项目关联人员...'
    this.pendingSlotMessages.push({ role: 'assistant', content: slotSummary })
    this.$nextTick(this.scrollToBottom)

    // 通过 Room/Tunnel 查询项目关联成员
    const projectResults = await dailyReportAiApis.resolveProjectMembers(result.project_names)
    const allNicknames = [...new Set(projectResults.flatMap(p => p.nicknames))].filter(Boolean)
    const hasRoomHit = projectResults.some(p => p.room_id && p.nicknames.length > 0)

    if (hasRoomHit && allNicknames.length > 0) {
        // 索引命中：用关联人员的花名拉原文日报
        this.messages[assistantIdx].content = slotSummary + `\n\n已找到 ${allNicknames.length} 名关联人员，正在同步日报数据...`
        this.$nextTick(this.scrollToBottom)

        const context = await this.fetchReportContext(allNicknames, result.period_start, result.period_end)
        if (!context) {
            this.messages[assistantIdx].content = slotSummary + '\n\n该项目在指定时间段内无日报更新。'
            this.syncPendingAssistant(assistantIdx)
            await this.flushSlotMessages()
            return
        }

        this.slotsConversationId = ''
        this.syncPendingAssistant(assistantIdx)
        await this.flushSlotMessages()
        this.reportContext = context
        await this.sendAskMessage(
            `请分析以上日报数据中关于项目「${result.project_names.join('、')}」的进展情况。`,
            false, 'project',
        )
    } else {
        // 索引未命中：降级走全局摘要 + 项目关键词
        this.messages[assistantIdx].content = slotSummary + '\n\n项目索引未命中，正在通过周摘要检索...'
        this.$nextTick(this.scrollToBottom)
        await this.handleGlobalQueryWithKeywords(result, assistantIdx, result.project_names, userText)
    }
}

