private async handlePersonQuery(result: ExtractSlotsResult, assistantIdx: number, userText: string) {
    const nicknames = this.resolveMembers(result)
    const memberLabel = result.member_type === 'group'
        ? `分组：${result.members.join('、')}`
        : `成员：${result.members.join('、')}`
    const countLabel = nicknames.length >= 10 ? `，共 ${nicknames.length} 人` : ''
    const periodLabel = `${result.period_start} ~ ${result.period_end}`
    const projectNote = result.project_names.length > 0 ? `\n关注项目：${result.project_names.join('、')}` : ''
    const slotSummary = `查询对象：${memberLabel}${countLabel}\n时间范围：${periodLabel}${result.period_raw ? `（${result.period_raw}）` : ''}${projectNote}`
    this.messages[assistantIdx].content = slotSummary + '\n\n正在同步日报数据...'
    this.pendingSlotMessages.push({ role: 'assistant', content: slotSummary })
    this.$nextTick(this.scrollToBottom)

    if (nicknames.length === 0) {
        const errMsg = `未找到匹配的成员「${result.members.join('、')}」，请尝试使用花名或先手动同步数据。`
        this.messages[assistantIdx].content = errMsg
        this.syncPendingAssistant(assistantIdx)
        await this.flushSlotMessages()
        return
    }

    const context = await this.fetchReportContext(nicknames, result.period_start, result.period_end)
    if (!context) {
        this.messages[assistantIdx].content = '该时间段内没有找到日报数据。'
        this.syncPendingAssistant(assistantIdx)
        await this.flushSlotMessages()
        return
    }

    this.slotsConversationId = ''
    this.syncPendingAssistant(assistantIdx)
    await this.flushSlotMessages()
    this.reportContext = context

    // 如果有项目维度，在 ask 消息中附加项目关注
    const projectFocus = result.project_names.length > 0
        ? `\n重点关注项目「${result.project_names.join('、')}」的相关工作。`
        : ''
    await this.sendAskMessage(
        `请分析以上日报数据。${projectFocus}`,
        false, 'person',
    )
}

