74→                    $resp = TransferRequestService::app()->transfer($request);
75→                    // 不同的站点可能会出错，因此后端的 code/msg 也放在 data 中一并返回
76→                    $ret['data'][$site] = $resp;
77→                    // GET 请求（查询日志）直接将后端接口返回的 data 内容输出到页面上
78→                }
79→                SiteService::app()->setSite($originalSite);
80→
81→                return $request->isMethod('get') ? response($ret['data'], 200, ['Content-Type' => 'text/html; charset=UTF-8']) : $this->responseJson($ret);
82→            }
83→
84→            $resp = TransferRequestService::app()->transfer($request);
85→            if (!is_array($resp)) {
86→                return $resp;
87→            }
88→
89→            // GET 请求（查询日志）直接将后端接口返回的 data 内容输出到页面上
90→            return $request->isMethod('get') ? response($resp['data'], 200, ['Content-Type' => 'text/html; charset=UTF-8']) : $this->responseJson($resp);
91→        }
92→
93→        return $next($request);
94→    }
