if (!function_exists('current_api_info')) {
    /**
     * 解析指定 path，并返回该 path 命中的路由信息。
     *
     * @param string $path 请求的 path，e.g. web-api/home/login
     * @return array 当前请求命中的路由的详细信息
     */
    function current_api_info(string $path = ''): array
    {
        $path = empty($path) ? request()->path() : $path;
        $first = strpos($path, '/');
        $prefix = substr($path, 0, $first);
        $uri = trim(substr($path, $first), '/');

        $routeConf = config("my_project.api_prefix_list.{$prefix}", []);
        if (empty($routeConf)) { // 找不到相应的 api_prefix 的话，返回空数组
            return [];
        }

        $matchedRouteConfigFile = 'my_'.str_replace('-', '_', $prefix);
        $apiConf = config("{$matchedRouteConfigFile}.{$uri}");

        // 默认同时支持 GET 和 POST 请求
        $methods = $apiConf['methods'] ?? ['get', 'post'];

        // 合并 $routeConf 和 $apiConf 的中间件配置
        $middlewares = $routeConf['middlewares'];
        $middlewares = array_merge($middlewares, $apiConf['middlewares'] ?? []);
        $middlewares = array_diff($middlewares, $apiConf['skip_middlewares'] ?? []);

        return [
            'api_prefix' => $prefix,
            'api_uri' => $uri,
            'methods' => $methods,
            'middlewares' => $middlewares,
            'route' => $apiConf['route'] ?? null,
            'params' => $apiConf['params'] ?? null,
            'owner_type' => $routeConf['owner_type'] ?? '',
            'auth_type' => $routeConf['auth_type'] ?? '',
        ];
    }
}

