18→     * Handle an incoming request.
19→     *
20→     * @param \Illuminate\Http\Request $request
21→     * @param \Closure(\Illuminate\Http\Request): (\Illuminate\Http\Response|\Illuminate\Http\RedirectResponse)  $next
22→     * @return \Illuminate\Http\JsonResponse|\Illuminate\Http\RedirectResponse|\Illuminate\Http\Response
23→     */
24→    public function handle(Request $request, Closure $next)
25→    {
26→        $params = $request->all();
27→        $client_secret = config('my_project.web_api.client_secret');
28→        $sign = '';
29→        if (isset($params['sign'])) {
30→            $sign = $params['sign'];
31→            unset($params['sign']);
32→        }
33→
34→        $params['api_secret'] = $client_secret;
35→        uksort($params, 'strcmp');
36→
37→        $newSign = md5(urldecode(http_build_query($params)));
